  void create_eas_database() {
    // Create the directory if it doesn't exist
    std::string dir = "data";
    if (!std::filesystem::exists(dir)) {
      std::filesystem::create_directories(dir);
    }

    // Create the empty database file
    std::string file = dir + "/eas_database.db";
    std::ofstream f(file);
    if (!f) {
      std::cerr << "Failed to create file: " << file << std::endl;
      return;
    }
    f.close();

    // Connect to the initial database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      std::cerr << "Failed to connect to test_db.sqlite" << std::endl;
      return;
    }
