#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Begin a transaction
  auto transaction_result = conn_result | sqlgen::begin_transaction;

  // 3. Delete users with last_login before 2025-01-01
  auto delete_result = transaction_result | 
                      (sqlgen::delete_from<User> | 
                       sqlgen::where("last_login"_c < "2025-01-01"));

  // 4. Commit the transaction
  auto commit_result = delete_result | sqlgen::commit;

  // 5. Return the commit result
  return commit_result ? 0 : 1;
}

} // namespace delete_inactive_users
```

