#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Drop existing tables if they exist
  (sqlgen::drop<Parent> | sqlgen::if_exists)(conn);
  (sqlgen::drop<Child> | sqlgen::if_exists)(conn);

  // 3. Create tables with proper constraints
  sqlgen::create_table<Parent>(conn);
  sqlgen::create_table<Child>(conn);

  // 4. Insert parent and child records
  std::vector<Parent> parents = {{1, "Parent 1"}, {2, "Parent 2"}};
  std::vector<Child> children = {{1, 1, "Child of Parent 1"}, {2, 1, "Another child of Parent 1"}, {3, 2, "Child of Parent 2"}};

  sqlgen::insert(parents)(conn);
  sqlgen::insert(children)(conn);

  // 5. Verify child count before deletion
  auto children_before = sqlgen::read<std::vector<Child>>(conn).value();
  size_t child_count_before = children_before.size();

  // 6. Delete parent and check if child records are automatically deleted
  sqlgen::delete_from<Parent>(conn);

  // 7. Verify deletion by checking child table count after deletion
  auto children_after = sqlgen::read<std::vector<Child>>(conn).value();
  size_t child_count_after = children_after.size();

  // 8. Return true if cascade delete works, false otherwise
  // Cascade works if all children were deleted when their parent was deleted
  // We check if the count decreased by the number of children that had the deleted parent
  size_t expected_deletion = std::count_if(children_before.begin(), children_before.end(),
                                          [](const Child& c) { return c.parent_id == 1; });

  return (child_count_after == child_count_before - expected_deletion);
}

}  // namespace cascade_delete_demo
