  auto conn = sqlite::connect("test_db.sqlite").value();

  const auto query =
      select_from<Sales>(weekday(col<"sale_time">) | as<"weekday">,
                         sum(col<"quantity">) | as<"total_quantity">) |
      group_by(col<"sale_time">) | to<std::vector<WeekdayStats>>;

  return query(conn).value();
