#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result.is_ok()) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = conn_result.value();

  // 2. Build the query using sqlgen::select_from with proper table aliases
  auto query = sqlgen::select_from<Project, "p">(
      "project_id"_t1 | sqlgen::as<"project_id">,
      "name"_t1 | sqlgen::as<"name">,
      sqlgen::day("start_time"_t2) | sqlgen::as<"day">,
      sqlgen::month("start_time"_t2) | sqlgen::as<"month">,
      sqlgen::year("start_time"_t2) | sqlgen::as<"year">,
      sqlgen::hour("start_time"_t2) | sqlgen::as<"hour">,
      sqlgen::minute("start_time"_t2) | sqlgen::as<"minute">,
      sqlgen::second("start_time"_t2) | sqlgen::as<"second">,
      sqlgen::days_between("start_time"_t2, "end_time"_t2) | sqlgen::as<"duration_days">
  )
  // 3. Add inner join between Project and TimeLog tables
  | sqlgen::inner_join<TimeLog, "t">("project_id"_t1 == "project_id"_t2)
  // 4. Add group_by with appropriate columns (project and week components)
  | sqlgen::group_by("project_id"_t1, 
                     sqlgen::week("start_time"_t2)) // Group by project and week
  // 5. Execute the query and return the results
  (conn);

  if (query.is_ok()) {
    return query.value();
  } else {
    return {}; // Return empty vector on query execution failure
  }
}

}  // namespace project_time_tracking
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Aliases**: Uses `"p"` for Project and `"t"` for TimeLog tables with proper literal syntax
3. **Field Selection**: Selects all required fields with proper aliasing using `sqlgen::as`
4. **Date Extraction**: Uses `sqlgen::day`, `sqlgen::month`, `sqlgen::year`, `sqlgen::hour`, `sqlgen::minute`, `sqlgen::second` functions
5. **Duration Calculation**: Uses `sqlgen::days_between` to compute duration between timestamps
6. **Inner Join**: Uses `sqlgen::inner_join` with proper join condition
7. **Grouping**: Groups by project ID and week using `sqlgen::group_by`
8. **Query Execution**: Executes the query and returns the results as `std::vector<TimeMetrics>`

The implementation follows the sqlgen library patterns demonstrated in the reference materials, using the pipe operator (`|`) to chain operations and proper function calls for each required operation.

